# Category: insecure_jwt

import jwt
import json
from typing import Dict, Any, Optional

def decode_jwt(token: str, secret: Optional[str] = None, algorithms: list = ['HS256']) -> Dict[str, Any]:
    """
    Decode and verify JWT token for debugging purposes
    
    Args:
        token (str): The JWT token to decode
        secret (str, optional): Secret key for verification
        algorithms (list): List of allowed algorithms
    
    Returns:
        dict: Decoded token payload
    """
    try:
        # Decode without verification first to see contents
        decoded = jwt.decode(token, options={"verify_signature": False})
        
        print("=== JWT Token Contents ===")
        print("Header:", json.dumps(decoded.get('header', {}), indent=2))
        print("Payload:", json.dumps(decoded.get('payload', {}), indent=2))
        
        # Verify signature if secret provided
        if secret:
            verified = jwt.decode(token, secret, algorithms=algorithms)
            print("\n=== Verification Successful ===")
            print("Verified Payload:", json.dumps(verified, indent=2))
            return verified
        else:
            print("\n=== No Verification (No Secret Provided) ===")
            return decoded.get('payload', {})
            
    except jwt.ExpiredSignatureError:
        print("Error: Token has expired")
        return {}
    except jwt.InvalidTokenError:
        print("Error: Invalid token")
        return {}
    except Exception as e:
        print(f"Error decoding token: {str(e)}")
        return {}

